using Microsoft.Dynamics.AX.Platform.Extensibility;

[ExportInterface]
internal abstract class ETGOTMSalesFormLetterService extends SysOperationServiceBase
{
    protected Args args;

}

Method.Source:
private void openSalesFormLetter()
{
    Set dataAreaSet = new Set(Types::String);                
    Common common;

    FormDataSource common_ds = FormDataUtil::getFormDataSource(args.record());            
    MultiSelectionHelper helper = MultiSelectionHelper::construct();

    helper.parmDatasource(common_ds);
    common = helper.getFirst();

    while (common.RecId != 0)
    {
        dataAreaSet = Set::union(dataAreaSet, ITMLine::dataAreaIdSetFromCommon(common));

        common = helper.getNext();
    }

    DataAreaId dataAreaId;
    SetEnumerator dataAreaSetEnum = dataAreaSet.getEnumerator();    

    while (dataAreaSetEnum.moveNext())
    {
        dataAreaId = dataAreaSetEnum.current();

        changeCompany (dataAreaId)
        {
            MenuFunction menuItem = new MenuFunction(this.menuItemName(), this.menuItemType());
            menuItem.run(args);
        }
    }
}
